CREATE TABLE `story_nodes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `story_id` int(11) NOT NULL,
  `node_key` varchar(50) NOT NULL COMMENT '节点业务编码，如 n1 / n_end / m1',
  `dialogue_text` text NOT NULL COMMENT '对话文案，可含换行符',
  `speaker` varchar(50) DEFAULT NULL COMMENT '说话人，前端字段名 character',
  `character_image_url` varchar(255) DEFAULT NULL COMMENT '人物立绘，前端字段名 characterImage',
  `bg_image_url` varchar(255) DEFAULT NULL COMMENT '背景图，前端字段名 bg',
  `is_end` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否结束节点，触发勋章发放',
  `sort_order` int(11) NOT NULL COMMENT '播放顺序，从 1 开始',
  `location_id` varchar(64) DEFAULT NULL COMMENT '剧情地图地点 ID，见 campus-map.js',
  `node_type` enum('scene','map','choice') NOT NULL DEFAULT 'scene' COMMENT '剧情页类型',
  `choices_json` json DEFAULT NULL COMMENT '分支选项 [{text,targetNodeId,requiresMajor,targetByCollege}]',
  `grants_badge` varchar(50) DEFAULT NULL COMMENT '到达此节点即发放的徽章 code',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_node_key` (`story_id`,`node_key`),
  UNIQUE KEY `uk_node_sort` (`story_id`,`sort_order`),
  CONSTRAINT `fk_node_story` FOREIGN KEY (`story_id`) REFERENCES `stories` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=659 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='剧情节点';
