INSERT INTO `badges` (`id`, `code`, `name`, `icon_url`, `description`, `condition_text`, `sort_order`, `detail`) VALUES (1,'badge_campus','🏛️ 校园探索者','/images/badge_campus.png','完成浏览校园剧情，熟悉校园环境','完成「浏览校园」剧情',1,NULL),(2,'badge_medical','🏥 医疗达人','/images/badge_medical.png','完成医保报销剧情，了解就医流程','完成「医保报销」剧情',2,NULL),(3,'badge_card','💳 补办高手','/images/badge_card.png','完成一卡通补办剧情，了解挂失流程','完成「一卡通补办」剧情',3,NULL),(4,'badge_print','🖨️ 打印能手','/images/badge_print.png','完成打印流程剧情，了解打印服务','完成「打印流程」剧情',4,NULL),(5,'badge_canteen_time','🍚 食堂时间通','/images/badge_campus.png','逛完校园食堂，掌握各食堂开放时间','完成「浏览校园」并逛过食堂区',10,'【食堂开放时间 · 来源：工大百科】\n北区餐厅：早7:00-9:00 / 午11:00-13:00 / 晚16:30-18:30\n北区餐车：周一至周五(除节假日)午11:00-12:30\n清真餐厅：7:00-20:30\n奥运餐厅：早7:00-9:00 / 午11:00-13:00 / 晚16:30-18:30\n南区餐车：周一至周五(除节假日)午11:00-12:30\n美食园餐厅：6:30-20:30；风味餐厅：9:00-22:00\n天天餐厅（学生服务楼二层）：午餐11:00-14:00 / 晚餐16:30-21:30\n天天咖啡厅：工作日7:00-21:00 / 周六日9:00-21:00（天天餐厅与天天咖啡厅是两个不同的地方）\n教工餐厅：早7:00-8:30 / 午11:00-13:00\n中蓝公寓餐厅：基本伙 早7:00-9:00/午11:00-13:00/晚16:30-18:30；风味档口7:00-21:00\n（校内食堂支持美团外卖送到宿舍楼下；具体以现场为准）'),(6,'badge_sports_time','🏃 运动时间通','/images/badge_campus.png','逛完运动场馆，掌握各场馆开放时间与预约','完成「浏览校园」并逛过运动区',11,'【运动场馆开放时间 · 来源：工大百科】\n预约：微信小程序「运动场地预约」，一卡通注册，每日7:00放号；累计3次爽约进黑名单(可到羽毛球馆前台申请解除)。\n北田径场：全天开放，免费\n南田径场：周一至周五6:00-18:00(实际全天开放)，免费\n篮球场/排球场：6:00-20:00（南操场南侧）\n网球场：6:00-20:00（南操场北侧）\n健身房：周一至周五10:00-22:00 / 周六日9:00-22:00（体育馆北4口，正对人文楼东门）\n乒乓球馆：周一二四17:00-20:00 / 周三六日12:00-20:00 / 周五16:00-20:00（南操场西侧地下一层）\n游泳馆：周一二四17:30-20:00 / 周三六日12:00-17:00,17:30-20:00 / 周五15:30-17:00,17:30-20:00（每场1.5h，首次需体检表）\n羽毛球馆：周一至周五10:00-22:00 / 周六日及节假日8:00-22:00（奥运场馆一层北一门）\n地下训练馆：优先保障课程与校队训练\n（各场馆价格分校内师生/亲友/校外，以百科「运动场地」页为准）'),(23,'badge_course_select','🎓 选课达人','/images/badge_course_select.png','完成选课攻略剧情，摸清三轮选课规则','完成「选课攻略」剧情',5,NULL),(24,'badge_overseas','✈️ 交流先锋','/images/badge_overseas.png','完成境外交流剧情，了解长期交流全流程','完成「境外交流」剧情',6,NULL),(25,'badge_plan','🧭 规划达人','/images/badge_plan.png','完成大学规划剧情，看清保研考研出国就业四条路','完成「大学规划」剧情',7,NULL);
/*!40000 ALTER TABLE `badges` ENABLE KEYS */;
UNLOCK TABLES;

LOCK TABLES `story_nodes` WRITE;
/*!40000 ALTER TABLE `story_nodes` DISABLE KEYS */;
INSERT INTO `story_nodes` (`id`, `story_id`, `node_key`, `dialogue_text`, `speaker`, `character_image_url`, `bg_image_url`, `is_end`, `sort_order`, `location_id`, `node_type`, `choices_json`, `grants_badge`) VALUES (14,4,'p1','同学需要打印吗？可以使用U盘或校园网传输文件。','店员',NULL,'/images/print_bg1.jpg',0,1,NULL,'scene',NULL,NULL),(15,4,'p2','选择好打印参数后，刷卡支付即可取走打印件。','店员',NULL,'/images/print_bg2.jpg',0,2,NULL,'scene',NULL,NULL),(16,4,'p_end','🎉 打印完成，祝你学习顺利！\n\n点击完成剧情，获得勋章！','店员',NULL,'/images/print_bg_end.jpg',1,3,NULL,'scene',NULL,NULL),(434,1,'life_welcome_scene','欢迎来到北京工业大学平乐园校区！我是你的向导学姐。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,1,NULL,'scene',NULL,NULL),(435,1,'life_gate_scene','先记住几个校门：东南西北四个大门，加上东南小门、西侧小门——迷路时找校门或体育场，方向就能重新对上；西侧小门离地铁近，但只走行人。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,2,NULL,'scene',NULL,NULL),(436,1,'life_gate_west_map','先看校园西侧：闪烁区域分别是西门和西侧小门。西侧小门离地铁更近，但只供行人通行。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,3,'campus_west_gate,campus_west_side_gate','map',NULL,NULL),(437,1,'life_gate_northeast_map','再看北门和东门：北门正对校医院方向，东门在校园东侧，都是辨认方向的重要地标。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,4,'campus_north_gate,campus_east_gate','map',NULL,NULL),(438,1,'life_gate_southeast_map','最后看南门和东南门：它们位于校园南侧，去南部教学区和生活区时很常用。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,5,'campus_south_gate,campus_southeast_gate','map',NULL,NULL),(439,1,'life_north_dorm_scene','先带你认认宿舍区。北区是 01 到 04 号楼，离学生综合服务中心很近。先把楼号、单元和门禁位置记牢，早八才不会手忙脚乱。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,6,'north_dormitories','scene',NULL,NULL),(440,1,'life_north_dorm_map','看这片闪烁的金色区域，它就是北区宿舍（01–04 号楼）；从学生综合服务中心出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,7,'north_dormitories','map',NULL,NULL),(441,1,'life_northeast_dorm_scene','东北区是 10、11 号楼，靠近北部教学区和北体育场。出门前预留十分钟，顺路熟悉银杏大道。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,8,'northeast_dormitories','scene',NULL,NULL),(442,1,'life_northeast_dorm_map','看这片闪烁的金色区域，它就是东北区宿舍（10、11 号楼）；从北体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,9,'northeast_dormitories','map',NULL,NULL),(443,1,'life_east_dorm_scene','东区是 13、14 号楼，靠近能源楼和北体育场。晚归时走照明充分的主路，也别忘了门禁时间。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,10,'east_dormitories','scene',NULL,NULL),(444,1,'life_east_dorm_map','看这片闪烁的金色区域，它就是东区宿舍（13、14 号楼）；从北体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,11,'east_dormitories','map',NULL,NULL),(445,1,'life_central_dorm_scene','中部是 07 到 12 号楼，是生活区的中转站，去图书馆、食堂和南体育场都很顺路。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,12,'central_dormitories','scene',NULL,NULL),(446,1,'life_central_dorm_map','看这片闪烁的金色区域，它就是中区宿舍（07–12 号楼）；从图书馆出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,13,'central_dormitories','map',NULL,NULL),(447,1,'life_south_dorm_scene','南区是 05、06 号楼，靠近南部教学区和奥林匹克体育馆，沿博雅路可以慢慢认清人文楼和科学楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,14,'south_dormitories','scene',NULL,NULL),(448,1,'life_south_dorm_map','看这片闪烁的金色区域，它就是南区宿舍（05、06 号楼）；从奥林匹克体育馆出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,15,'south_dormitories','map',NULL,NULL),(449,1,'life_service_center_scene','这栋是学生综合服务楼。北区食堂、民族食堂、天天餐厅都在这一带，第一次来先认认楼层。它们的开放时间我整理进了「食堂时间徽章」，逛完点开就能看。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,16,'student_service_center','scene',NULL,NULL),(450,1,'life_service_center_map','看这片闪烁的金色区域，它就是学生综合服务楼；从北区宿舍出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,17,'student_service_center','map',NULL,NULL),(451,1,'life_olympic_rest_scene','奥运餐厅在 12 号宿舍楼南侧。赶课时优先选离自己最近的食堂，别为吃什么耽误上课。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,18,'olympic_restaurant','scene',NULL,NULL),(452,1,'life_olympic_rest_map','看这片闪烁的金色区域，它就是奥运餐厅；从南区宿舍出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,19,'olympic_restaurant','map',NULL,NULL),(453,1,'life_food_court_scene','美食园、风味餐厅、教工餐厅还有天天咖啡厅集中在餐饮综合楼一带。提醒一下：天天餐厅和天天咖啡厅是两个不同的地方哦。晚自习前想补给能量可以来看看。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,20,'food_court','scene',NULL,NULL),(454,1,'life_food_court_map','看这片闪烁的金色区域，它就是美食园（餐饮综合楼）；从奥运餐厅出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,21,'food_court','map',NULL,NULL),(455,1,'life_express_scene','快递驿站在北侧田径场和游泳馆之间、游泳馆后面。快递地址统一填：北京市朝阳区南磨房镇平乐园100号。快递柜 24 小时开，驿站 9:00–19:00。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,22,'express_station','scene',NULL,NULL),(456,1,'life_express_map','看这片闪烁的金色区域，它就是快递驿站；从游泳馆出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,23,'express_station','map',NULL,NULL),(457,1,'life_hospital_scene','校医院就在北门门口。关注公众号「北京工业大学医院」就能预约挂号，到院凭一卡通签到就诊；不舒服时别硬撑，尽早来看看。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,24,'school_hospital','scene',NULL,NULL),(458,1,'life_hospital_map','看这片闪烁的金色区域，它就是校医院；从北门出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,25,'school_hospital','map',NULL,NULL),(459,1,'choose_interest','生活区先逛到这。接下来想先去哪边？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,26,NULL,'choice','[{\"text\": \"先去学习区看看\", \"targetNodeId\": \"study_profile_gate\"}, {\"text\": \"先去运动区转转\", \"targetNodeId\": \"sport_north_scene\"}]','badge_canteen_time'),(460,1,'sport_north_scene','北体育场是北部最醒目的方向参照，全天开放。经过训练场地时，记得给上课和校队训练留出空间。各场馆详细的开放时间和价格，我整理进了「运动时间徽章」。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,27,'north_sports_ground','scene',NULL,NULL),(461,1,'sport_north_map','看这片闪烁的金色区域，它就是北体育场；从北区宿舍出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,28,'north_sports_ground','map',NULL,NULL),(462,1,'sport_south_scene','南体育场也免费开放。跑步前先看有没有教学、比赛或大型活动安排。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,29,'south_sports_ground','scene',NULL,NULL),(463,1,'sport_south_map','看这片闪烁的金色区域，它就是南体育场；从奥运餐厅出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,30,'south_sports_ground','map',NULL,NULL),(464,1,'sport_ballcourt_scene','篮球场、排球场在南操场南侧、奥运餐厅东南侧，每天 6:00–20:00。热门时段建议提前约同学，实际可用以预约小程序为准。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,31,'basketball_volleyball_courts','scene',NULL,NULL),(465,1,'sport_ballcourt_map','看这片闪烁的金色区域，它就是篮球场、排球场；从南体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,32,'basketball_volleyball_courts','map',NULL,NULL),(466,1,'sport_tennis_scene','网球场在南操场北侧，每天 6:00–20:00。校内外收费不同，练球前先确认预约和当天规则。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,33,'tennis_courts','scene',NULL,NULL),(467,1,'sport_tennis_map','看这片闪烁的金色区域，它就是网球场；从南体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,34,'tennis_courts','map',NULL,NULL),(468,1,'sport_gym_scene','奥林匹克体育馆里有健身房（北 4 口，正对人文楼东门）和羽毛球馆（一层北一门进）。两处都要留意预约和开放时间。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,35,'olympic_venue','scene',NULL,NULL),(469,1,'sport_gym_map','看这片闪烁的金色区域，它就是奥林匹克体育馆；从南区宿舍出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,36,'olympic_venue','map',NULL,NULL),(470,1,'sport_pingpong_scene','乒乓球馆在南田径场看台下、南操场西侧地下一层，有 23 张专业球台。认准地图上的红色不规则长条，就不会绕圈。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,37,'table_tennis_hall','scene',NULL,NULL),(471,1,'sport_pingpong_map','看这片闪烁的金色区域，它就是乒乓球馆；从南体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,38,'table_tennis_hall','map',NULL,NULL),(472,1,'sport_swim_scene','游泳馆在北体育场西侧。首次游泳健身要带体检表；每场次 1.5 小时，注意清场时间。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,39,'swimming_pool','scene',NULL,NULL),(473,1,'sport_swim_map','看这片闪烁的金色区域，它就是游泳馆；从北体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,40,'swimming_pool','map',NULL,NULL),(474,1,'sport_underground_scene','地下训练馆在游泳馆北侧，有篮球、排球场地，但会优先保障课程和校队训练。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,41,'underground_training_hall','scene',NULL,NULL),(475,1,'sport_underground_map','看这片闪烁的金色区域，它就是地下训练馆；从游泳馆出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,42,'underground_training_hall','map',NULL,NULL),(476,1,'sport_end_choice','运动区就逛到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,43,NULL,'choice','[{\"text\": \"再去看看学习区\", \"targetNodeId\": \"study_profile_gate\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]','badge_sports_time'),(477,1,'study_profile_gate','学习区的楼很多，我按你的专业带你走，只逛跟你相关的学院楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,44,NULL,'choice','[{\"text\": \"按我的专业继续\", \"targetNodeId\": \"study_library_scene\", \"requiresMajor\": true, \"targetByCollege\": {\"交通\": \"major_traffic_scene\", \"会计\": \"major_econ_scene\", \"光电\": \"major_physics_scene\", \"力学\": \"major_mathstat_scene\", \"土木\": \"major_civileng_scene\", \"数学\": \"major_mathstat_scene\", \"机械\": \"major_mech_scene\", \"材料\": \"major_material_scene\", \"法学\": \"major_econ_scene\", \"物理\": \"major_physics_scene\", \"生物\": \"major_lifesci_scene\", \"社会\": \"major_econ_scene\", \"管理\": \"major_econ_scene\", \"经济\": \"major_econ_scene\", \"统计\": \"major_mathstat_scene\", \"艺术\": \"major_art_scene\", \"英语\": \"major_foreign_scene\", \"设计\": \"major_art_scene\", \"软件\": \"major_cs_scene\", \"通信\": \"major_infosci_scene\", \"金融\": \"major_econ_scene\", \"外国语\": \"major_foreign_scene\", \"建筑学\": \"major_archurban_scene\", \"物联网\": \"major_cs_scene\", \"给排水\": \"major_civileng_scene\", \"自动化\": \"major_infosci_scene\", \"计算机\": \"major_cs_scene\", \"人工智能\": \"major_infosci_scene\", \"信息安全\": \"major_cs_scene\", \"城乡规划\": \"major_archurban_scene\", \"城市规划\": \"major_archurban_scene\", \"建筑工程\": \"major_civileng_scene\", \"建筑环境\": \"major_civileng_scene\", \"数据科学\": \"major_mathstat_scene\", \"智能制造\": \"major_mech_scene\", \"智能建造\": \"major_civileng_scene\", \"环境工程\": \"major_environ_scene\", \"环境科学\": \"major_environ_scene\", \"生命科学\": \"major_lifesci_scene\", \"电子信息\": \"major_infosci_scene\", \"信息科学技术\": \"major_infosci_scene\"}}, {\"text\": \"先看通用学习路线\", \"targetNodeId\": \"study_library_scene\"}]',NULL),(478,1,'study_library_scene','图书馆大致每天 7:30–22:30 开放，凭一卡通进入；不同区域规则可直接问工作人员。资源紧张时，也能上教务系统查空教室自习。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,45,'library','scene',NULL,NULL),(479,1,'study_library_map','看这片闪烁的金色区域，它就是图书馆；从知新园出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,46,'library','map',NULL,NULL),(480,1,'study_teach1_scene','一教靠近北体育场西侧，数理和部分理工课常在这里。上课前确认教室号，别只看楼名。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,47,'no1_teaching_building','scene',NULL,NULL),(481,1,'study_teach1_map','看这片闪烁的金色区域，它就是第一教学楼；从北体育场往西走，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,48,'no1_teaching_building','map',NULL,NULL),(482,1,'study_teach2_scene','二教和一教相连，材料楼在南侧；赶课时预留上下楼和找教室的时间。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,49,'no2_teaching_building','scene',NULL,NULL),(483,1,'study_teach2_map','看这片闪烁的金色区域，它就是第二教学楼；从第一教学楼出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,50,'no2_teaching_building','map',NULL,NULL),(484,1,'study_teach3_scene','三教在图书馆东北侧，是许多专业都会用到的公共教学楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,51,'no3_teaching_building','scene',NULL,NULL),(485,1,'study_teach3_map','看这片闪烁的金色区域，它就是第三教学楼；从图书馆出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,52,'no3_teaching_building','map',NULL,NULL),(486,1,'study_teach4_scene','四教靠近南体育场，文科和艺术类课程较常出现，也可顺路熟悉艺术广场。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,53,'no4_teaching_building','scene',NULL,NULL),(487,1,'study_teach4_map','看这片闪烁的金色区域，它就是第四教学楼；从南体育场出发，很快就能找到入口。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,54,'no4_teaching_building','map',NULL,NULL),(488,1,'study_generic_end_choice','通用路线就到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,55,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(489,1,'major_cs_scene','作为计算机学院的同学，你常去的是实训楼、信息楼和软件楼；另外三教、四教是公用教学楼，很多课都在那儿上。先带你认认自己学院的楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,56,NULL,'scene',NULL,NULL),(490,1,'major_cs_shixun_map','看这片闪烁的金色区域，它就是实训楼；在环能楼东南、月亮湖东侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,57,'practice_training_building','map',NULL,NULL),(491,1,'major_cs_info_map','看这片闪烁的金色区域，它就是信息楼；从图书馆往西、秋实路东侧就到。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,58,'information_building','map',NULL,NULL),(492,1,'major_cs_software_map','看这片闪烁的金色区域，它就是软件楼；在环能楼东南、月亮湖东侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,59,'software_building','map',NULL,NULL),(493,1,'major_cs_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,60,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(494,1,'major_infosci_scene','作为信息科学技术学院的同学，你常去的是信息楼、信息楼东和实训楼；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,61,NULL,'scene',NULL,NULL),(495,1,'major_infosci_info_map','看这片闪烁的金色区域，它就是信息楼；从图书馆往西、秋实路东侧就到。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,62,'information_building','map',NULL,NULL),(496,1,'major_infosci_infoeast_map','看这片闪烁的金色区域，它就是信息楼东；就在信息楼旁边、被 C 形结构包着的小楼，找教室要留意。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,63,'information_building_east','map',NULL,NULL),(497,1,'major_infosci_shixun_map','看这片闪烁的金色区域，它就是实训楼；在环能楼东南、月亮湖东侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,64,'practice_training_building','map',NULL,NULL),(498,1,'major_infosci_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,65,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(499,1,'major_mech_scene','作为机械与能源工程学院的同学，你常去机电楼、智研楼、金工楼和能源楼；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,66,NULL,'scene',NULL,NULL),(500,1,'major_mech_jidian_map','看这片闪烁的金色区域，它就是机电楼；在校区西北、北区宿舍以西一带。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,67,'mechanical_electrical_building','map',NULL,NULL),(501,1,'major_mech_zhiyan_map','看这片闪烁的金色区域，它就是智研楼；在图书馆正北、第一教学楼西南侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,68,'intelligent_research_building','map',NULL,NULL),(502,1,'major_mech_jingong_map','看这片闪烁的金色区域，它就是金工楼；从北体育场往北、学生公寓 11 北侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,69,'goldworking_building','map',NULL,NULL),(503,1,'major_mech_energy_map','看这片闪烁的金色区域，它就是能源楼；在北体育场东南、学生公寓 14 南侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,70,'energy_building','map',NULL,NULL),(504,1,'major_mech_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,71,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(505,1,'major_material_scene','作为材料科学与工程学院的同学，你常去材料楼；三教、四教是公用教学楼。先带你去认认材料楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,72,NULL,'scene',NULL,NULL),(506,1,'major_material_map','看这片闪烁的金色区域，它就是材料楼；在图书馆往北、第二教学楼南侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,73,'material_building','map',NULL,NULL),(507,1,'major_material_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,74,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(508,1,'major_civileng_scene','作为建筑工程学院的同学，你常去建工楼和城建楼；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,75,NULL,'scene',NULL,NULL),(509,1,'major_civileng_jiangong_map','看这片闪烁的金色区域，它就是建工楼；在校区西侧、材料楼往西一带。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,76,'construction_building','map',NULL,NULL),(510,1,'major_civileng_chengjian_map','看这片闪烁的金色区域，它就是城建楼；在环能楼东南、月亮湖东侧的校区东南边缘。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,77,'urban_construction_building','map',NULL,NULL),(511,1,'major_civileng_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,78,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(512,1,'major_archurban_scene','作为建筑与城市规划学院的同学，你常去建工楼和城建楼；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,79,NULL,'scene',NULL,NULL),(513,1,'major_archurban_jiangong_map','看这片闪烁的金色区域，它就是建工楼；在校区西侧、材料楼往西一带。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,80,'construction_building','map',NULL,NULL),(514,1,'major_archurban_chengjian_map','看这片闪烁的金色区域，它就是城建楼；在环能楼东南、月亮湖东侧的校区东南边缘。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,81,'urban_construction_building','map',NULL,NULL),(515,1,'major_archurban_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,82,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(516,1,'major_traffic_scene','作为城市交通学院的同学，你会在城建楼和实训楼附近接触智慧城市、交通规划与实践训练；三教、四教是公用教学楼。先带你去认认这两处。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,83,NULL,'scene',NULL,NULL),(517,1,'major_traffic_map','看这片闪烁的金色区域，它就是城建楼；在月亮湖东侧的东南边缘教学区。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,84,'urban_construction_building','map',NULL,NULL),(518,1,'major_traffic_end','再看旁边的实训楼。这里与城建楼相邻，是交通方向进行实践训练的重要地点。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,85,'practice_training_building','map','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(519,1,'major_mathstat_scene','作为数学统计学与力学学院的同学，你常去数理楼，一教也常有你们的课；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,86,NULL,'scene',NULL,NULL),(520,1,'major_mathstat_shuli_map','看这片闪烁的金色区域，它就是数理楼；在图书馆往北、游泳馆西侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,87,'physical_science_building','map',NULL,NULL),(521,1,'major_mathstat_teach1_map','看这片闪烁的金色区域，它就是第一教学楼；从北体育场往西走就到。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,88,'no1_teaching_building','map',NULL,NULL),(522,1,'major_mathstat_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,89,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(523,1,'major_physics_scene','作为物理与光电工程学院的同学，你常去数理楼；三教、四教是公用教学楼。先带你去认认数理楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,90,NULL,'scene',NULL,NULL),(524,1,'major_physics_map','看这片闪烁的金色区域，它就是数理楼；在图书馆往北、游泳馆西侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,91,'physical_science_building','map',NULL,NULL),(525,1,'major_physics_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,92,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(526,1,'major_lifesci_scene','作为化学与生命科学学院的同学，你常去生命楼；三教、四教是公用教学楼。先带你去认认生命楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,93,NULL,'scene',NULL,NULL),(527,1,'major_lifesci_map','看这片闪烁的金色区域，它就是生命楼；在数理楼往南、环能楼北侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,94,'life_science_building','map',NULL,NULL),(528,1,'major_lifesci_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,95,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(529,1,'major_environ_scene','作为环境科学与工程学院的同学，你常去环能楼，能源楼也会用到；三教、四教是公用教学楼。先带你认认。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,96,NULL,'scene',NULL,NULL),(530,1,'major_environ_huanneng_map','看这片闪烁的金色区域，它就是环能楼；在生命楼往南、实训楼北侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,97,'environment_energy_building','map',NULL,NULL),(531,1,'major_environ_energy_map','看这片闪烁的金色区域，它就是能源楼；在北体育场东南、学生公寓 14 南侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,98,'energy_building','map',NULL,NULL),(532,1,'major_environ_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,99,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(533,1,'major_econ_scene','作为经济与管理学院的同学（社会学、法学等也在这个学院），你常去经管楼；三教、四教是公用教学楼。先带你去认认经管楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,100,NULL,'scene',NULL,NULL),(534,1,'major_econ_map','看这片闪烁的金色区域，它就是经管楼；在秋实路东侧、科学楼往西。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,101,'economics_management_building','map',NULL,NULL),(535,1,'major_econ_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,102,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(536,1,'major_foreign_scene','作为外国语学院的同学，你常去人文楼；三教、四教是公用教学楼。先带你去认认人文楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,103,NULL,'scene',NULL,NULL),(537,1,'major_foreign_map','看这片闪烁的金色区域，它就是人文楼；在博雅路南侧、奥林匹克体育馆西南侧。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,104,'humanities_building','map',NULL,NULL),(538,1,'major_foreign_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,105,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(539,1,'major_art_scene','作为艺术设计学院的同学，你常去艺术楼；四教也常有你们的课。先带你去认认艺术楼。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,106,NULL,'scene',NULL,NULL),(540,1,'major_art_map','看这片闪烁的金色区域，它就是艺术楼；在第四教学楼往南、艺术广场中心。','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,107,'art_building','map',NULL,NULL),(541,1,'major_art_end','你学院的楼就先认到这。接下来？','学姐','/images/character_xuejie.png','/images/story_bg1.jpg',0,108,NULL,'choice','[{\"text\": \"再去运动场转转\", \"targetNodeId\": \"sport_north_scene\"}, {\"text\": \"结束本次浏览\", \"targetNodeId\": \"campus_end\"}]',NULL),(542,1,'campus_end','今天的校园浏览先到这里。地图上的每一栋楼，都可能成为你第一次上课、运动或和朋友见面的起点；带着它再走一遍，你很快会拥有自己的校园路线。\n\n点击完成，领取勋章！','学姐','/images/character_xuejie.png','/images/story_bg_end.jpg',1,109,NULL,'scene',NULL,NULL),(549,2,'m1','同学你好，我是校医院的王医生。医保报销看起来步骤不少，但只要先选对就医路线、再把材料带齐，就不会手忙脚乱。我们一步一步来。','校医',NULL,'/images/medical_bg1.jpg',0,1,'school_hospital','scene',NULL,NULL),(550,2,'m2','先做个小自检：这套流程适用于已注册的统招本科生、研究生，以及因病休学保留学籍、毕业一年内未就业且仍符合待遇条件的同学。拿不准时，可以在企业微信搜索“小百科”咨询。','校医',NULL,'/images/medical_bg1.jpg',0,2,NULL,'scene',NULL,NULL),(551,2,'m3','无论走哪条路线，先记住三件事：带好校园一卡通和身份证；到校外医院挂号、缴费时主动说明“公费医疗，走自费结算”；绝对不要使用医保卡（社保卡），否则这笔费用不能再按公费医疗报销。','校医',NULL,'/images/medical_bg1.jpg',0,3,NULL,'scene',NULL,NULL),(552,2,'m4_situation_choice','现在的情况更接近哪一种？','校医',NULL,'/images/medical_bg1.jpg',0,4,NULL,'choice','[{\"text\": \"工作日普通门诊\", \"targetNodeId\": \"m5_workday_booking\"}, {\"text\": \"周末、节假日或寒暑假普通门诊\", \"targetNodeId\": \"m8_rest_choice\"}, {\"text\": \"突发急症，需要马上就医\", \"targetNodeId\": \"m11_emergency_nearby\"}, {\"text\": \"已经需要住院或医生建议住院\", \"targetNodeId\": \"m13_inpatient_rule\"}]',NULL),(553,2,'m5_workday_booking','工作日看普通门诊，顺序不能反：先在“北京友谊医院”小程序或 App 挂好西城院区、通州院区的门诊号；确认有号后，再带着一卡通到校医院就诊。','校医',NULL,'/images/medical_bg2.jpg',0,5,'school_hospital','scene',NULL,NULL),(554,2,'m6_workday_referral','校医院医生会根据病情判断是否需要外转。需要转诊时，医生会开具盖章有效的《公费医疗转诊单》。这张单不能补开，所以没有转诊单就不要自行去校外看普通门诊。','校医',NULL,'/images/medical_bg2.jpg',0,6,'school_hospital','scene',NULL,NULL),(555,2,'m7_workday_visit','带身份证和转诊单前往友谊医院；取号、缴费时仍选择“自费”通道。校医院就诊通常报销 95%，经转诊到友谊医院门诊通常报销 90%。发票、明细、处方和病历都要保留好。','校医',NULL,'/images/medical_bg2.jpg',0,7,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"继续准备普通门诊报销材料\", \"targetNodeId\": \"m17_material_outpatient\"}]',NULL),(556,2,'m8_rest_choice','周末、法定节假日或寒暑假看普通门诊时，一般不需要先到校医院开转诊单。你现在是在北京，还是已经离京返乡？','校医',NULL,'/images/medical_bg2.jpg',0,8,NULL,'choice','[{\"text\": \"在北京，准备去友谊医院\", \"targetNodeId\": \"m9_rest_friendship\"}, {\"text\": \"寒暑假已离京，出现急症\", \"targetNodeId\": \"m10_rest_away\"}]',NULL),(557,2,'m9_rest_friendship','周末、法定节假日或寒暑假，可直接持身份证到友谊医院就诊，挂“自费”号即可，无需转诊单；符合条件的门急诊通常按 90% 报销。','校医',NULL,'/images/medical_bg2.jpg',0,9,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"继续准备普通门诊报销材料\", \"targetNodeId\": \"m17_material_outpatient\"}]',NULL),(558,2,'m10_rest_away','寒暑假离京后，只能到居住地附近的医保定点医院看急诊；发热、肠道门诊也按急诊处理。急诊通常报销 50%，普通门诊仅限 30 元封顶。记得保留所有急诊材料。','校医',NULL,'/images/medical_bg2.jpg',0,10,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"继续准备急诊报销材料\", \"targetNodeId\": \"m18_material_emergency\"}]',NULL),(559,2,'m11_emergency_nearby','突发急症时，优先就近去医保定点医院的急诊科，并在窗口说明“公费医疗，自费结算”。急诊只限报销一所医院，同一次情况不要同时跑多家医院。','校医',NULL,'/images/medical_bg3.jpg',0,11,NULL,'scene',NULL,NULL),(560,2,'m12_emergency_special','垂杨柳医院不是合同医院：工作日去急诊通常需要校医院提前转诊，符合条件时可按 70% 报销；寒暑假或节假日直接急诊则按 50% 执行。若病情危重需要住院，可以先就近救治，出入院时都要声明公费医疗身份。','校医',NULL,'/images/medical_bg3.jpg',0,12,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"继续准备急诊报销材料\", \"targetNodeId\": \"m18_material_emergency\"}]',NULL),(561,2,'m13_inpatient_rule','计划住院原则上应入住友谊医院，或入住经校医院转诊的指定专科医院。周末、节假日、寒暑假因急诊住院时，可以入住非合同医院的医保定点机构；超过规定标准的床位费需自行承担。','校医',NULL,'/images/medical_bg3.jpg',0,13,NULL,'scene',NULL,NULL),(562,2,'m14_inpatient_loan_choice','如果住院费用压力较大，是否需要了解住院借款？','校医',NULL,'/images/medical_bg3.jpg',0,14,NULL,'choice','[{\"text\": \"需要了解住院借款\", \"targetNodeId\": \"m15_inpatient_loan\"}, {\"text\": \"不需要，继续准备住院报销材料\", \"targetNodeId\": \"m16_inpatient_next\"}]',NULL),(563,2,'m15_inpatient_loan','借款仅限住院：凭住院通知单填写借款单，并缴纳借款额 20% 的押金。3 万元以下由校医院院长审批，3 万元以上需主管校领导审批；毕业生离校前两个月原则上不办理。','校医',NULL,'/images/medical_bg3.jpg',0,15,NULL,'scene',NULL,NULL),(564,2,'m16_inpatient_next','住院路线已经说明完毕。接下来想继续了解其他就医情形，还是准备住院报销材料？','校医',NULL,'/images/medical_bg3.jpg',0,16,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"继续准备住院报销材料\", \"targetNodeId\": \"m19_material_inpatient\"}]',NULL),(565,2,'m17_material_outpatient','校外普通门诊材料：发票、收费明细清单、处方底方（开药时）、门诊病历；工作日门诊还必须附转诊单。材料可在医院自助机打印；友谊医院的电子发票、病历和检验报告通常在就诊 24 小时后可从小程序下载打印。','校医',NULL,'/images/medical_bg1.jpg',0,17,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"材料齐了，进入提交与审核步骤\", \"targetNodeId\": \"m20_submit\"}]',NULL),(566,2,'m18_material_emergency','急诊材料：发票、收费明细清单、急诊处方、急诊诊断证明、急诊病历。缺少其中任何一项都可能影响审核；异地就医还需要当地医院为医保定点医院的证明。','校医',NULL,'/images/medical_bg1.jpg',0,18,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"材料齐了，进入提交与审核步骤\", \"targetNodeId\": \"m20_submit\"}]',NULL),(567,2,'m19_material_inpatient','住院材料：住院发票、盖医保章的费用明细清单、出院诊断证明，以及转诊单或急诊入院证明。若是外伤、休学、异地或因公外出，还要按情况补交相应证明。','校医',NULL,'/images/medical_bg1.jpg',0,19,NULL,'choice','[{\"text\": \"再了解其他就医情形\", \"targetNodeId\": \"m4_situation_choice\"}, {\"text\": \"材料齐了，进入提交与审核步骤\", \"targetNodeId\": \"m20_submit\"}]',NULL),(568,2,'m20_submit','材料准备好后，要在费用发生当月或下一个自然月内提交；12 月发票最晚可延至次年 3 月 31 日。校本部在学综楼 4 层公费医疗报销窗口办理；通州校区在每周三下午、耕园图书馆后侧办理。','校医',NULL,'/images/medical_bg1.jpg',0,20,'student_service_center','scene',NULL,NULL),(569,2,'m21_review','审核时还会看药量：急性病一般不超过 3 日量，慢性病不超过 7 日量，行动不便不超过 2 周量；部分慢病稳定期最多 1 个月量。一张处方最多 5 种药，超量部分需要自付。','校医',NULL,'/images/medical_bg1.jpg',0,21,NULL,'scene',NULL,NULL),(570,2,'m22_result','最后耐心等审核：门诊报销款通常在次月 3 日前打入校园卡关联账户；住院报销款通常在次月 11 日前到账。','校医',NULL,'/images/medical_bg1.jpg',0,22,NULL,'scene',NULL,NULL),(571,2,'m_end','这次医保报销流程就带你走完了。记住口诀：先选对路线，校外走自费；单据全留好，按时去提交。\n\n点击完成，领取勋章！','校医',NULL,'/images/medical_bg_end.jpg',1,23,NULL,'scene',NULL,NULL),(578,3,'card1','oi！看什么呢……校园卡？正好跟你说说一卡通的事，刚开学丢卡的人特别多。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,1,NULL,'scene',NULL,NULL),(579,3,'card2','先说明白，一卡通是你在这学校最重要的东西。食堂吃饭、进图书馆、刷校门和操场门禁、期末体测，全靠它，不带卡基本寸步难行。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,2,NULL,'scene',NULL,NULL),(580,3,'card3','实体卡报到时学院会发。同时登录\"日新工大\"APP，里面有\"校园码/虚拟卡\"，能刷手机支付，忘带卡时能顶上。两个是同一账户、余额互通。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,3,NULL,'scene',NULL,NULL),(581,3,'card4','一卡通初始密码是身份证后六位（带X的试试0或1）。注意这是消费超限额时输的密码，不是登录密码，别搞混。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,4,NULL,'scene',NULL,NULL),(582,3,'card5','拿到卡第一件事——改密码。\"日新工大\"APP或校内自助机都能改，改完记牢。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,5,NULL,'scene',NULL,NULL),(583,3,'card6','接下来重点说丢了怎么办，这个你大概率用得上，先记住。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,6,NULL,'scene',NULL,NULL),(584,3,'card7','第一步别急着补。先去\"校园喵\"论坛或贴吧的\"失物招领\"看看，很多人捡到卡会发帖；没有就自己发一条，写清时间、地点、姓名、学号。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,7,NULL,'scene',NULL,NULL),(585,3,'card8','第二步，一两天没找到就去自助补卡机。北工大补卡机不少——知新园、三教、四教、北区餐厅西侧、学综楼四层，主要楼宇基本都有。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,8,NULL,'scene',NULL,NULL),(586,3,'card9','补卡流程：身份证放读卡区，输学号和密码，按提示挂失、确认身份、扣费11元（从一卡通余额扣），扣完当场出卡，余额实时转到新卡。全程三五分钟。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,9,NULL,'scene',NULL,NULL),(587,3,'card10','如果余额不够11元，先在\"日新工大\"APP用支付宝或微信充值再补，不然机器会卡住。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,10,NULL,'scene',NULL,NULL),(588,3,'card11','补卡遇到问题——身份证读不出、系统报错，打 67392429，或直接去知新园101一卡通服务大厅，工作日8:00到17:00有人。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,11,NULL,'scene',NULL,NULL),(589,3,'card12','对了，补卡后旧实体卡自动作废，捡到也没用，不用管它。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,12,NULL,'scene',NULL,NULL),(590,3,'card13','最后提醒：卡别弯折、别打孔、别靠强磁场，里面是芯片，坏了补卡照样收费。平时放卡套里，别跟钥匙手机塞一起，能少丢几次。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,13,NULL,'scene',NULL,NULL),(591,3,'card_end','就这些。吃饭去吧，食堂刷你的新卡试试灵不灵。\n\n点击完成剧情，获得勋章！','学姐','/images/character_xuejie.png','/images/story_bg_end.jpg',1,14,NULL,'scene',NULL,NULL),(592,17,'cs1','看到从三教涌出来这拨人了吗？认识环境、办手续都只是前菜，你们真正的大学节奏从这个画面开始。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,1,NULL,'scene',NULL,NULL),(593,17,'cs2','这个点多半是刚下选修课。你现在课表只有必修，觉得课不多，等选课一开，你也会像他们一样在几个教学楼之间来回跑。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,2,NULL,'scene',NULL,NULL),(594,17,'cs3','趁现在把选课说清楚。先讲底层规则：必修是教务处直接置入课表的，不用你管。你要自己选的是三类——专选、通识、校选。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,3,NULL,'scene',NULL,NULL),(595,17,'cs4','专选就是专业选修课。选课时选好年级和专业，系统只显示你下学期能选的专选。很多专业大二上还没开多少，先别急；开出好几门也不是全选，照培养计划挑。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,4,NULL,'scene',NULL,NULL),(596,17,'cs5','通识是公共选修课，大二开始能选。不影响保研排名，但影响GPA。想出国的会专挑给分高的通识刷加权。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,5,NULL,'scene',NULL,NULL),(597,17,'cs6','校选是选别的专业的课。经管、社会学类普遍比工科好拿分。25届能不能用本专业专选抵校选，说法有分歧，直接问教务最稳。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,6,NULL,'scene',NULL,NULL),(598,17,'cs7','每学期选课学分上限30分。修不够不能毕业，超过34分你会累到不行，一般按28到30走。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,7,NULL,'scene',NULL,NULL),(599,17,'cs8','选课分三轮，规则不一样，搞清楚再动手。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,8,NULL,'scene',NULL,NULL),(600,17,'cs9','第一轮预选：不限容量、选多少都行，最后系统随机抽签。所以第一轮尽量多选提高中签率；不想要的课必须这轮退掉，到正选就退不了了。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,9,NULL,'scene',NULL,NULL),(601,17,'cs10','第二轮正选：先退课后抢课。退课窗口是第一轮中签但不想要的课最后的退出机会，错过就关死。退课结束才是正选抢课，有容量、先到先得。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,10,NULL,'scene',NULL,NULL),(602,17,'cs11','正选有个关键点：很多人12点半进去没好课就放弃了，但下午两点前后系统会集中释放退课余量，那才是捡漏窗口。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,11,NULL,'scene',NULL,NULL),(603,17,'cs12','正选后人太少的课会被关：专选少于15人且不足班级一半、通识少于15人都会关。被波及就第三轮补选找课，先到先得。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,12,NULL,'scene',NULL,NULL),(604,17,'cs13','转专业进来的，补修课程先去学院教务科做课程冲抵，确认缺什么再选，别自己直接冲。跟班重修若和正常课冲突，可申请免听不免考，填表备案即可。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,13,NULL,'scene',NULL,NULL),(605,17,'cs14','操作上：校内从 my.bjut.edu.cn 走统一认证，校外用 webvpn。选课界面筛选Tag里把\"推荐选课\"删掉，能看到的课更多。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,14,NULL,'scene',NULL,NULL),(606,17,'cs15','每学期选完去\"学生学业情况查询\"看还缺什么，别等大四才发现学分不够。经管类通识可抵通识任意选修学分，其他类型能不能抵——问教务。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,15,NULL,'scene',NULL,NULL),(607,17,'cs16','还有，别找人代选，也别帮别人选，账号自己管好。选课时间不固定，每次期末考完看教务处通知，自己盯着，别指望有人提醒你。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,16,NULL,'scene',NULL,NULL),(608,17,'cs_end','差不多了。你现在还没开始上课，先对选课有个概念，等能选了再细讲也不迟。\n\n点击完成剧情，获得勋章！','学姐','/images/character_xuejie.png','/images/story_bg_end.jpg',1,17,NULL,'scene',NULL,NULL),(609,18,'ov1','你翻的什么……境外交流手册？行，你开始看这个了。趁现在把长期境外交流的流程讲一遍，提前知道比临时跑手续省事得多。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,1,NULL,'scene',NULL,NULL),(610,18,'ov2','先说什么时间能申请。长期境外交流的通知每学期初前几周发，申请的是下一学期出去。申秋季学期可选一学期或一学年；申春季学期只能一学期。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,2,NULL,'scene',NULL,NULL),(611,18,'ov3','本科阶段总共最长只能申请一年境外交流。大二到大四是主要窗口，大一太早，基本没项目开放给大一。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,3,NULL,'scene',NULL,NULL),(612,18,'ov4','流程第一步：等学校发布项目通知，看这学期有哪些学校、哪些专业能申请，选一个你符合条件的报名。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,4,NULL,'scene',NULL,NULL),(613,18,'ov5','学校审核通过，校内流程就走完了。但要提醒你——这是两条线：北工大同意你去、境外学校也同意你去。校内过了还得申请对方项目、拿到录取，两边都成才真能出去。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,5,NULL,'scene',NULL,NULL),(614,18,'ov6','校内申请走网上办事大厅，发起长期境外交流申请。审批：辅导员→学院教务科→专业负责人→学院外事秘书→学院外事领导→国际交流合作处，走完大概一个月内。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,6,NULL,'scene',NULL,NULL),(615,18,'ov7','国际处通过后会反馈给学院和你本人，这时才能继续办境外学校那边的申请。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,7,NULL,'scene',NULL,NULL),(616,18,'ov8','收到境外学校录取通知书后，还有几件必须做的事。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,8,NULL,'scene',NULL,NULL),(617,18,'ov9','第一，参加国际处的行前说明会，必须去，不去不派出。国际处在科学楼221。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,9,NULL,'scene',NULL,NULL),(618,18,'ov10','第二，在网上办事大厅办休学申请，出国前必须完成，没办休学不派出，具体问教务处。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,10,NULL,'scene',NULL,NULL),(619,18,'ov11','第三，签《学生出国（境）交流协议书》，国际处会通知你签。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,11,NULL,'scene',NULL,NULL),(620,18,'ov12','出发前还有件很重要的事——学分兑换。提前和学院教务科商量好境外哪些课能兑换北工大哪些课。境外期间算休学，要么用境外课程抵学分、要么回来补修，必须出发前形成书面计划。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,12,NULL,'scene',NULL,NULL),(621,18,'ov13','好消息：形势与政策可在境外完成；大四毕设也能在国外做，但要满足\"项目类课程+有论文+有答辩\"三个条件才能抵毕设，缺一个回来还得补。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,13,NULL,'scene',NULL,NULL),(622,18,'ov14','境外期间每月底填《境外交流学生情况月度反馈表》交给学院外事秘书。回国前记得问外方要官方成绩单，寄给国际处或让对方发国际处邮箱电子版。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,14,NULL,'scene',NULL,NULL),(623,18,'ov15','回国后：第一，网上办事大厅办复学；第二，提交回访表和入境记录；第三，去国际处做成绩单认证。认证也要去科学楼一趟，不是你自己拿着成绩单就能找学院换学分。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,15,NULL,'scene',NULL,NULL),(624,18,'ov16','钱的事：项目分自费和免学费两种，不管哪种，北工大学费都要正常交。同时不管自费公费都能申请境外交流奖学金。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,16,NULL,'scene',NULL,NULL),(625,18,'ov17','奖学金分长期短期。长期分特等、一等、二等，金额一万到三万，看GPA和排名；申请时间等国际处通知。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,17,NULL,'scene',NULL,NULL),(626,18,'ov18','补充：大二能申到的项目看专业，大二下比大二上多些，但主要是大三出去的多；大二报要确认学分够、专业课前置满足。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,18,NULL,'scene',NULL,NULL),(627,18,'ov19','奖学金条件：特等要GPA3.5以上或专业前15%、且去世界前100合作校；一等GPA3.0以上或前30%；二等GPA2.7以上或前40%。短期项目五千，线上短期按团费30%给、封顶三千。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,19,NULL,'scene',NULL,NULL),(628,18,'ov_end','行，大概就这些。这流程跨度很长，大二大三再具体看通知就行，现在知道几个关键节点、别临时抱佛脚就好。\n\n点击完成剧情，获得勋章！','学姐','/images/character_xuejie.png','/images/story_bg_end.jpg',1,20,NULL,'scene',NULL,NULL),(629,19,'plan1','你大一课表看着挺松吧？其实平乐园08:00上第一节课。北区宿舍到一教5分钟，南区到一教10到15分钟，算好时间起床，别迟到。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,1,NULL,'scene',NULL,NULL),(630,19,'plan2','食堂早餐窗口多数07:00到09:00，09:00后不补餐；美食园06:30到20:30全天有，但品种少。记住这俩时间，开学第一周别饿着。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,2,NULL,'scene',NULL,NULL),(631,19,'plan3','不过今天聊的不是上课，是上课之外的事。大学四年，你要在教务系统完成三个硬指标——第二课堂学分、志愿时长、创新学分，缺任何一个，拿不到学位证。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,3,NULL,'scene',NULL,NULL),(632,19,'plan4','第二课堂分德智体美劳五个方向，每方向1到2分，看学院培养方案；参加一次活动给0.1到0.5分。信息在班级群、学院公众号、\"学习通\"发布。大一大二每学期参加3到5次基本就够，别堆到后期。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,4,NULL,'scene',NULL,NULL),(633,19,'plan5','志愿时长不低于20小时，具体看学院。迎新、校运会、图书馆整理都算，校青协和学院志愿部会发招募。大一大二顺带做，每次2到4小时，一年凑够没问题。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,5,NULL,'scene',NULL,NULL),(634,19,'plan6','创新学分：大创项目春季立项，学科竞赛（挑战杯、互联网+、数学建模）、发论文、申专利都能拿。哪些算分、要多少分，查学院培养计划或问辅导员，每个学院不一样。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,6,NULL,'scene',NULL,NULL),(635,19,'plan7','以上是所有人必须完成的底线。下面说你未来的方向——大四去向大概深造、出国、就业各三分之一，所以大二结束前最好定一条主路径：保研、考研、出国、就业。四条准备节奏完全不同。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,7,NULL,'scene',NULL,NULL),(636,19,'plan_hub1','四条路各不相同，你想先听哪条？可以都听完再决定。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,8,NULL,'choice','[{\"text\": \"A. 保研\", \"targetNodeId\": \"plan_by1\"}, {\"text\": \"B. 考研\", \"targetNodeId\": \"plan_ky1\"}, {\"text\": \"C. 出国\", \"targetNodeId\": \"plan_ab1\"}, {\"text\": \"D. 就业\", \"targetNodeId\": \"plan_job1\"}, {\"text\": \"E. 我心里有数，直接收尾\", \"targetNodeId\": \"plan_end1\"}]',NULL),(637,19,'plan_by1','先说保研。看大一到大三GPA，专业排名前10%到15%才有推免资格；六级必须过425；有挂科或处分一票否决。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,9,NULL,'scene',NULL,NULL),(638,19,'plan_by2','时间线：大一到大三上每学期稳住绩点、每门课都重要（含通识）；大二起每年1到2个竞赛或科研；大三上9到10月梳理成果、定目标院校导师；大三下3到4月备个人陈述和推荐信、关注夏令营；6到7月参加夏令营，拿优秀营员基本等于预录取；大四上9月推免资格认定、填国家系统。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,10,NULL,'scene',NULL,NULL),(639,19,'plan_by3','真实情况：要用三年保持高绩点，竞赛科研说是\"加分\"其实是\"标配\"，没有科研经历保外校很难。另外大三下成绩仍算保研GPA、不能放松；9月学院公布推免细则以当年文件为准；没拿到理想夏令营，9月底还有预推免。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,11,NULL,'scene',NULL,NULL),(640,19,'plan_by_back','保研就说到这。还想看别的路线吗？','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,12,NULL,'choice','[{\"text\": \"再看看别的路线\", \"targetNodeId\": \"plan_hub1\"}, {\"text\": \"够了，收尾吧\", \"targetNodeId\": \"plan_end1\"}]',NULL),(641,19,'plan_ky1','再说考研。大三下3月开始系统复习，12月底初试。核心是提前把大三下和大四上的课表清空。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,13,NULL,'scene',NULL,NULL),(642,19,'plan_ky2','时间线：大一到大三上正常上课但尽量提前修学分，确保大三下不超过三门；大三上10到12月定目标院校专业、查科目和参考书；寒假开始背单词、复习数学基础；大三下3到6月基础每天4到6小时；暑假7到8月强化每天8到10小时、别安排实习旅游；大四上9到10月冲刺真题加政治，10月研招网报名，12月倒数第二个周末初试，次年3到4月复试。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,14,NULL,'scene',NULL,NULL),(643,19,'plan_ky3','考研是信息战：大三上就要定专业课范围，别拖到大三下。考前3到4周持续高压，其他事全暂停。报名时确认院校专业代码，报错没法改，招生简章9月发布注意看科目有无调整。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,15,NULL,'scene',NULL,NULL),(644,19,'plan_ky_back','考研就说到这。还想看别的路线吗？','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,16,NULL,'choice','[{\"text\": \"再看看别的路线\", \"targetNodeId\": \"plan_hub1\"}, {\"text\": \"够了，收尾吧\", \"targetNodeId\": \"plan_end1\"}]',NULL),(645,19,'plan_ab1','再说出国。看四年全部课程GPA（体育、通识、政治都算），目标3.5以上；语言成绩和软背景都要提前准备。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,17,NULL,'scene',NULL,NULL),(646,19,'plan_ab2','时间线：大一下到大二上了解目标国家学校要求、定托福还是雅思；大二全年备考，暑假或大三上首考；大三上判断要不要二刷，GRE/GMAT需要就安排在大三下；暑假或寒假做科研实习提升背景；大三下定2到3位专业课教授当推荐人、提前打招呼；暑假写文书初稿、语言最后冲刺；大四上9到10月定校网申、提交第一批。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,18,NULL,'scene',NULL,NULL),(647,19,'plan_ab3','提醒：大二结束还没开始语言，大三会很紧；推荐信别等申请季前两周才找教授。美国要个人陈述和简历、多数12到1月截止，英国港新滚动录取越早越好；定校时保底、匹配、冲刺校各2到3所；跟踪推荐信提交状态，推荐人没按时交等于作废。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,19,NULL,'scene',NULL,NULL),(648,19,'plan_ab_back','出国就说到这。还想看别的路线吗？','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,20,NULL,'choice','[{\"text\": \"再看看别的路线\", \"targetNodeId\": \"plan_hub1\"}, {\"text\": \"够了，收尾吧\", \"targetNodeId\": \"plan_end1\"}]',NULL),(649,19,'plan_job1','再说直接就业。企业看实习、项目和技能，绩点不挂科能毕业就行。但实习要求连续3个月左右，得提前规划课表。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,21,NULL,'scene',NULL,NULL),(650,19,'plan_job2','时间线：大一下到大二上学岗位技能（校内一般不教）——技术岗学编程框架/数据库/刷算法（LeetCode 200题以上、GitHub有项目），非技术岗学产品工具/设计/数据分析；大二暑假第一段实习，不求大厂、有经历就比空白强；大三积累技能做项目；大三暑假是关键实习期，暑期实习3到5月启动、有转正机会；大四上9到10月秋招黄金期，11到12月补录，大四下3到4月春招。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,22,NULL,'scene',NULL,NULL),(651,19,'plan_job3','大四上课表必须空出来，秋招要跑宣讲、笔试、面试常请假。大三就关注招聘动态、学简历和面试。技术岗大三就在牛客网刷面经，非技术岗大二做一份目标岗位相关的项目或作品，面试能拿出来讲。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,23,NULL,'scene',NULL,NULL),(652,19,'plan_job_back','就业就说到这。还想看别的路线吗？','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,24,NULL,'choice','[{\"text\": \"再看看别的路线\", \"targetNodeId\": \"plan_hub1\"}, {\"text\": \"够了，收尾吧\", \"targetNodeId\": \"plan_end1\"}]',NULL),(653,19,'plan_end1','不用太紧张，这四条路你现在不用定死，但至少要知道每条的门槛在哪。最后给你几个大学最该想清楚的提醒。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,25,NULL,'scene',NULL,NULL),(654,19,'plan_end2','第一，课表不等于你的一天。上课只占每天三分之一到一半，剩下的时间——下午没课、晚上、周末——决定了你大四的出路，从第一周就规划课余时间。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,26,NULL,'scene',NULL,NULL),(655,19,'plan_end3','第二，学分和绩点是两回事。修满学分是及格线，绩点高才有选择权——保研、转专业、出国都看绩点。大一绩点是后面所有竞争的基础，别想着先混混。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,27,NULL,'scene',NULL,NULL),(656,19,'plan_end4','第三，能在大三前完成的别拖到大四。四六级、第二课堂、志愿时长、创新学分、主要专业课全部提前做，每学期开学看一眼\"学生学业情况查询\"，知道自己还缺什么。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,28,NULL,'scene',NULL,NULL),(657,19,'plan_end5','第四，时间冲突不可避免，没人能什么都做。想清楚主路径是什么，把时间优先给主路径上的事。','学姐','/images/character_xuejie.png','/images/story_bg_default.jpg',0,29,NULL,'scene',NULL,NULL),(658,19,'plan_end6','具体到\"创新学分怎么录\"\"我这个专业保研比例多少\"这类细节，辅导员和学院教务最权威，比任何学长学姐都准，不确定就直接问。行了，回去慢慢想，大一第一周理清楚，后面三年轻松很多。\n\n点击完成剧情，获得勋章！','学姐','/images/character_xuejie.png','/images/story_bg_end.jpg',1,30,NULL,'scene',NULL,NULL);
/*!40000 ALTER TABLE `story_nodes` ENABLE KEYS */;
UNLOCK TABLES;

LOCK TABLES `process_markers` WRITE;
/*!40000 ALTER TABLE `process_markers` DISABLE KEYS */;
INSERT INTO `process_markers` (`id`, `code`, `name`, `description`, `steps`, `position_x`, `position_y`, `short_story_id`, `status`, `sort_order`) VALUES (1,'medical','🏥 医保报销流程','了解校医院就诊和医保报销的完整流程','[\"在校医院挂号就诊\", \"医生开具转诊单（如需外院就诊）\", \"持转诊单到指定医院就诊\", \"收集发票、病历等材料\", \"返校提交报销材料到校医院窗口\", \"等待审核，报销款打入银行卡\"]',20.50,45.30,2,'enabled',1),(2,'card','💳 一卡通补办','校园一卡通丢失后如何快速补办','[\"在校园卡服务中心挂失\", \"缴纳工本费（现金/微信）\", \"现场拍照制卡\", \"领取新卡，激活使用\"]',62.00,30.00,3,'enabled',2),(3,'print','🖨️ 校园打印流程','如何在校园内使用打印服务','[\"前往校园打印店或图书馆打印区\", \"连接校园网或使用U盘\", \"上传/选择打印文件\", \"设置打印参数（单双面、份数等）\", \"刷卡或扫码支付\", \"取走打印件\"]',45.00,70.00,4,'hidden',3),(13,'course_select','🎓 选课攻略','专选/通识/校选怎么选、三轮选课怎么抢','[\"分清专选、通识、校选三类\", \"第一轮预选尽量多选（抽签）\", \"第二轮先退课后抢课，下午两点捡漏余量\", \"人少的课会被关，第三轮补选\", \"选完查学业情况看还缺什么\"]',50.00,50.00,17,'enabled',4),(14,'overseas_exchange','✈️ 境外交流','长期境外交流从申请到回国的完整流程','[\"看通知选符合条件的项目报名\", \"校内网上办事大厅逐级审批到国际处\", \"拿到境外学校录取\", \"行前说明会+办休学+签协议+学分兑换\", \"境外每月反馈，回国办复学、成绩单认证\"]',42.00,78.00,18,'enabled',5);
/*!40000 ALTER TABLE `process_markers` ENABLE KEYS */;
UNLOCK TABLES;

