INSERT INTO `kb_entries` (`id`, `category`, `question`, `answer`, `keywords`, `contact`, `source`, `images`, `status`, `updated_at`, `created_at`) VALUES (8,'办事流程','医保报销怎么办理','医保报销流程：1) 在校医院挂号就诊；2) 如需外院就诊，由医生开具转诊单；3) 持转诊单到指定医院就诊；4) 收集发票、病历等材料；5) 返校后到校医院报销窗口提交材料；6) 等待审核，报销款打入银行卡。','医保 报销 就医 转诊 发票 校医院','','探校之旅办事流程',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(9,'工大百科','工大百科','点击下方👇链接👇即可查看对应内容~\n\n热门问题\n\n新生答疑\n\n宿舍介绍\n\n组织和社团\n\n信息服务\n\n好好学习\n\n经验分享\n\n温暖工大\n\n编写中。。。\n\n百科介绍\n\n这是一本关于北工大的百科全书，里面包含了从你入校、宿舍生活、社团活动、学习、选修课、竞赛、转专业、保研、国际交流、医疗报销、等等几乎所有你在工大可能会遇上的问题，让你的大学生活拥有开挂一般的体验。\n\n请一定利用好【搜索】和【切换页面】功能，不然你会迷失在知识的海洋中！\n\n【搜索】\n\n【切换页面】\n\n校园社区\n\n于此同时，喵喵还有一个校园社区【校园喵mini】，这里的每一位同学都非常友好、和善、大家互帮互助，共同进步，也欢迎你加入~','工大百科','','工大百科(学生整理)','[{\"url\": \"/kb-images/a8520811fe2db15e.jpg\", \"desc\": \"腾讯文档「工大百科」小程序首页截图，红色标注指示如何打开菜单进行搜索。\"}, {\"url\": \"/kb-images/560b19e7068da2f4.jpg\", \"desc\": \"两张「工大百科」文档界面截图，左图为首页栏目列表，右图为展开的页面目录，红字标注切换页面与展开子页面的操作。\"}]','enabled','2026-07-14 23:30:42','2026-07-14 15:44:34'),(10,'热门问题','热门问题','本章节介绍一下喵喵经常被问到的问题\n\n最新校历\n\n校园一卡通如何补办？\n\n学生证如何补办？\n\n校车（班车）时间表\n\n师生亲友入校预约\n\n校门开放时间表\n\n浴室开放时间\n\n食堂开放时间\n\n健康证\n\n校内网换绑手机号\n\n教务处位置及联系方式','热门问题','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(11,'热门问题','最新校历','校历解释\n\n中秋、国庆等法定节假日都是正常放假的，图上没标红而已，是否调休到时候看具体的放假通知\n\n（PS：往年清明、五一都没有调休，希望今年继续保持！）\n\n17-19 周是考试周或小学期\n\n（如果你的专业没有考试，或者考试很少，那你的寒假此时就可以开始啦 ）','热门问题 最新校历','','工大百科(学生整理)','[{\"url\": \"/kb-images/310492cf3278e34b.jpg\", \"desc\": \"2025-2026学年第一学期校历表（含节假日标注）\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(12,'热门问题','校园一卡通如何补办？','校园一卡通是我校师生的校内“身份证”日常校园内的生活都需要它，但天天带着，总是会有那么几次不小心把它弄丢了，该咋办？\n\n社区求助\n\n发现丢卡了，不用担心！\n\n先到校园喵论坛 #失物招领 话题下看看有没有好心人已经捡到\n\n或者自己发一条帖子添加话题 #我丢东西了 在线寻卡（描述清除丢卡时间、地点、学部及姓名等信息）\n\n自助补卡机\n\n输入学号和密码后，点击确定后将身份证放在右上身份证读卡区，身份信息验证无误后点击挂失后即可自助补卡\n\n自助补卡出现问题可以联系 67392429\n\n一卡通初始密码为身份证后六位，其中有X的话试试0或者1\n\n补卡费用收取成本 11 元/卡，补卡后账户金额实时到账，自助机办完当场即可拿到新卡\n\n现场服务\n\n网络与信息技术中心校园一卡通服务大厅办公地址、电话和时间\n\n地 址：平乐园校区知新园 101 室\n\n电 话：010-67392429\n\n时 间：工作日 8:00-12:00，13:30-17:00\n\n知新园位置如下所示，就在图书馆和7号楼之间\n\n参考资料\n\n《校园网IT使用指南2024.pdf》','热门问题 校园一卡通如何补办？','','工大百科(学生整理)','[{\"url\": \"/kb-images/ddd1cadf3ce5a4e6.jpg\", \"desc\": \"校园自助补卡终端设备照片及其触摸屏界面（自助服务系统主界面和自助补卡流程界面）。\"}, {\"url\": \"/kb-images/fd2d97c3786f76cb.jpg\", \"desc\": \"「自助机（自助补卡终端和自助圈存终端）分布情况」表格，列出各校区楼宇的自助设备类别、数量及补卡类型。\"}, {\"url\": \"/kb-images/7149e9975ec517e5.jpg\", \"desc\": \"校园3D立体地图局部，红圈标注「知新园」位置，周围为逸夫图书馆、第三教学楼及各号宿舍楼。\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(13,'热门问题','学生证如何补办？','有的同学用学生证买车票，有的同学用学生证打窝，有的同学用学生证炫耀，学生证表示太容易丢了，已老实，求放过，那么本章教大家如何补办学生证！\n\n一、打开企业微信\n\n二、填写个人信息（如下）\n\n三、审核通过后，将1寸白底照片交至学综楼4层一站式服务大厅（导航软件可搜）\n\n四、等待通知领取学生证','热门问题 学生证如何补办？','','工大百科(学生整理)','[{\"url\": \"/kb-images/9fb251c9fe0163a8.jpg\", \"desc\": \"手机App工作台界面截图，标注如何找到本科学生证补办入口\"}, {\"url\": \"/kb-images/bbf37e62885132d9.jpg\", \"desc\": \"本科学生证补办申请表单界面截图，含填写项与办理说明\"}]','enabled','2026-07-14 23:30:42','2026-07-14 15:44:34'),(14,'热门问题','校车（班车）时间表','为了方便通州校区和本部师生的通勤，学校特此设置了班车\n\n发车时间表\n\n工作日\n\n温馨提示：周六日可自行乘坐地铁通勤，或者到校园喵论坛添加话题 #拼车 找小伙伴一起打车\n\n发车地点\n\n通州发车地点在汲学楼正门\n\n本部在逸夫图书馆北侧秋实广场\n\n常见问题\n\n班车收费吗？\n\n工大师生持一卡通免费乘车\n\n班车需要多久？\n\n不堵车的话单程40分钟左右\n\n班车上可以带行李箱吗？\n\n和平常大巴一样可携带行李箱\n\n每次发车有几俩班车？\n\n每个发车时间点只有一辆班车\n\n参考资料\n\n日新工大 - 班车查询','热门问题 校车（班车）时间表','','工大百科(学生整理)','[{\"url\": \"/kb-images/34193bb6c543a22b.jpg\", \"desc\": \"校本部与通州校区之间校车（班车）发车时间表\"}, {\"url\": \"/kb-images/87cb1e83a6ddac9e.jpg\", \"desc\": \"校园三维地图局部，标注秋实广场及周边建筑\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(15,'热门问题','师生亲友入校预约','如果需要带自己的家人朋友进校参观，则需要提前预约，本文介绍两种预约方法。\n\n日新工大APP\n\n一站式 - 师生亲友入校预约\n\n在顶部搜索框输入“师生亲友”\n\n内网信息门户\n\nhttps://my.bjut.edu.cn\n\n网上办事 - 师生亲友入校预约申请\n\n常见问题\n\n可以预约本部吗？\n\n预约系统是通用的，本部、通州都可以预约使用\n\n是否需要提前预约？\n\n为确保顺利入校，请至少提前一天预约\n\n如何判断是否预约成功？\n\n预约成功后亲友会收到短信提醒，到时候刷身份证入校即可\n\n一次预约是否可以多次进校？\n\n一次预约申请仅供亲友入校一次，如需下次入校，请重新预约\n\n预约了但实际未去是否有影响？\n\n预约后如无法入校无任何影响\n\n亲友是否可以开车入校？\n\n通州、中蓝无法停车，本部停车请导航到东南门，停车按时收费\n\n参考资料\n\n春暖花开！和北工大约起来～','热门问题 师生亲友入校预约','','工大百科(学生整理)','[{\"url\": \"/kb-images/8bff1355ecef2f75.jpg\", \"desc\": \"「网上办事大厅/一网通办」App首页截图，含我的收藏与热门服务列表，红框标注底部中间的按钮。\"}, {\"url\": \"/kb-images/9a2fb1aa594834e1.jpg\", \"desc\": \"服务大厅搜索界面截图，搜索框输入「师生亲友」，红框标注搜索结果「师生亲友入校预约申请」。\"}, {\"url\": \"/kb-images/992f9b3dd91fa748.jpg\", \"desc\": \"内网综合门户网页截图，左侧导航栏红框标注「网上办事」，右侧为用户信息面板（个人信息已打码）。\"}, {\"url\": \"/kb-images/c33ace83c1649989.jpg\", \"desc\": \"网上办事服务卡片列表截图，红框标注「师生亲友入校预约申请」卡片，展示各服务办理时限、办理量及承办部门。\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(16,'热门问题','校门开放时间表','校门名称\n\n开放时间\n\n备注\n\n西门\n\n00:00-24:00\n\n东南门\n\n05:50-23:00\n\n东门\n\n06:00-23:00\n\n机动车仅出口\n\n北门\n\n06:00-23:00\n\n仅行人出入\n\n南门\n\n06:00-23:00\n\n西区东门\n\n00:00-24:00\n\n地铁站南侧围墙小门\n\n06:00-24:00\n\n仅本校师生出入\n\n中蓝公寓南门\n\n00:00-24:00','热门问题 校门开放时间表','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(17,'热门问题','浴室开放时间','9月1号后浴室开放时间\n\n南区浴室\n\n星期一~星期六 10:00--22:30\n星期日 12:00--22:30 浴室23:00关门（22:30停止进入）\n\n北区浴室\n\n星期日~星期五 10:00--22:30\n星期六 12:00--22:30 浴室23:00关门（22:30停止进入)\n\n1号男生宿舍楼浴室\n\n19:00-22:00\n\n2号男生宿舍楼浴室\n\n19:00-22:00\n\n3号女生宿舍楼浴室\n\n19:00-22:00\n\n4号女生宿舍楼浴室\n\n19:00-22:00','热门问题 浴室开放时间','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(18,'热门问题','食堂开放时间','北区餐厅\n\n开餐时间：\n\n早餐：7:00-9:00；\n\n午餐：11:00-13:00；\n\n晚餐：16:30-18:30\n\n北区餐车\n\n开餐时间：\n\n周一至周五（除节假日）午餐：11:00-12:30\n\n清真餐厅\n\n开餐时间：7:00-20:30\n\n奥运餐厅\n\n开餐时间：\n\n早餐：7:00-9:00；\n\n午餐：11:00-13:00；\n\n晚餐：16:30-18:30\n\n南区餐车\n\n开餐时间：周一至周五（除节假日）午餐：11:00-12:30\n\n美食园餐厅、风味餐厅\n\n开餐时间：\n\n美食园餐厅：6:30-20:30；\n\n风味餐厅：    9:00-22:00\n\n天天咖啡厅\n\n开餐时间：\n\n天天咖啡厅：工作日：7：00-21：00；周六日： 9：00-21：00\n\n教工餐厅：早餐：7:00-8:30；午餐：11:00-13:00\n\n中蓝公寓餐厅\n\n开餐时间：\n\n基本伙：\n\n早餐：7:00-9:00\n\n午餐：11:00-13:00\n\n晚餐：16:30-18:30；\n\n风味档口：7:00-21:00','热门问题 食堂开放时间','','工大百科(学生整理)','[{\"url\": \"/kb-images/a2b29d7fa795c47d.jpg\", \"desc\": \"学生综合服务楼（Student Service Bldg.）外景照片，含思源路、学子路路口指示牌。\"}, {\"url\": \"/kb-images/0e4f6bc113d0e9f2.jpg\", \"desc\": \"快餐车（餐车）照片，蓝色车身，三名工作人员在车内售卖餐食，旁立指示牌。\"}, {\"url\": \"/kb-images/c3e877946a527cdc.jpg\", \"desc\": \"清真食堂建筑外景照片，红砖楼体，正门上方有金色「清真食堂」牌匾。\"}, {\"url\": \"/kb-images/3b27ca647967152b.jpg\", \"desc\": \"奥运餐厅外景照片，红砖建筑，门前设可乐遮阳棚展位。\"}, {\"url\": \"/kb-images/67a4cabada74c0c0.jpg\", \"desc\": \"风味餐厅/美食园（新沐兰）建筑外景，楼下挂有节能横幅。\"}, {\"url\": \"/kb-images/e511fac8d5560c71.jpg\", \"desc\": \"美食园与天天咖啡厅门面照片，右侧立有营业时间指示牌。\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(19,'热门问题','健康证','1、校医院五层保健科（504）领体检表和收费单\n\n2、到一层收费处交体检费20元（一卡通、微信、支付宝、现金）\n\n3、二层 体检项目：\n\n注意：科室不用挂号，人少直接进，人多在门外排队即可\n\n内科检查：自助量血压，医生听心跳\n\n外科检查：医生看脚底（脚气）\n\n4、五层 体检完到保健科（504）领取体检合格证\n\n5、体检时间：周一、周二、周四、周五全天办理\n\n上午8:00-11:30\n\n下午13:30-16:30','热门问题 健康证','','工大百科(学生整理)','[{\"url\": \"/kb-images/625eb32709c3d2ce.jpg\", \"desc\": \"医院体格检查表（办游泳证用）及体检缴费治疗单实拍照片\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(20,'新生答疑','新生答疑','作为刚入校的萌新们，肯定对学校充满了好奇，本章节就全面的介绍你在工大生活学习的方方面面\n\n帮助你快速融入工大大家庭，更好的在工大生活学习~\n\n校园地图\n\n快递地址\n\n运动场地\n\n上课时间以及课表说明\n\n学校常用公众号\n\n校园网、VPN、校园卡都是啥？\n\n学号各个数字的含义\n\n学院划分及专业方向\n\n2024级新生课表\n\n校园防骗手册','新生答疑','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(21,'新生答疑','校园地图','静态地图仅供参考，大家可下载高德地图、腾讯地图等APP获取更好的导航体验\n\n本部地图\n\n3D地图\n\n手绘风\n\n平面图\n\n下图标注了体育课上课地点\n\nVR地图\n\n也可以看看 360° 全景 VR 校园地图\n\n特殊说明\n\n五人制足球馆：就在游泳池后面，快递驿站旁边的地下，校园喵社区同学拍的照片如下：\n\n形体礼仪教室：进快递驿站，里面有一个长走廊，右转尽头就到了\n\n信北阶：信息楼北部阶梯教室\n\n通州校区\n\n北京工业大学通州校区\n北京工业大学通州校区 - 720云VR全景制作网\nhttps://www.720yun.com/t/90vktmpe5fq','新生答疑 校园地图','','工大百科(学生整理)','[{\"url\": \"/kb-images/ba083c1b32fa4619.jpg\", \"desc\": \"校园地图（三维立体渲染版），标注各楼宇、宿舍、校门位置\"}, {\"url\": \"/kb-images/4ac4fc4b1b2865b4.jpg\", \"desc\": \"本部（平乐园校区）平面手绘地图，标注楼宇、操场、餐厅、校门\"}, {\"url\": \"/kb-images/3e1d8f38e1cc4ea7.jpg\", \"desc\": \"平乐园校区总平面图（矢量彩色版，文字较小不清晰）\"}, {\"url\": \"/kb-images/5a8487746c0a6ec8.jpg\", \"desc\": \"平乐园校区总平面图（带体育课程/场地标注版）\"}, {\"url\": \"/kb-images/e160a0dea4aff778.jpg\", \"desc\": \"VR校园全景入口图（经管楼中庭室内全景照片）\"}, {\"url\": \"/kb-images/c26ef4aa8334f04a.jpg\", \"desc\": \"三维校园地图局部放大图，红色箭头指向信息楼附近位置\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(22,'新生答疑','快递地址','本部\n\n地址：北京北京市朝阳区南磨房镇平乐园100号北京工业大学\n\n位置：游泳馆后面快递驿站、快递柜\n\n时间：快递柜24小时开放，驿站：9:00-19:00\n\n中蓝\n\n地址：北京市朝阳区西大望路27号北京工业大学中蓝公寓\n\n位置：蓝晖园旁边，中蓝自习室斜对面\n\n介绍：快递服务站共有柜机4组，格口1500个。目前大部分快递例如：中通，圆通，申通，韵达，顺丰，京东，丹鸟，极兔快递等均可入站，少部分例如：德邦物流于中蓝校区南门口摆摊。\n\n通州\n\n地址：北京市通州区永顺镇潞苑南大街1145号北京工业大学通州校区\n\n位置：学校北门快递柜（所有快递及大部分外卖）\n\n时间：室外智能自提柜24小时开放， 室内取件和寄件服务开放时间： 8:30-22:30\n\n参考资料\n\n校会·迎新 | 平乐园校区指南\n\n速看！中蓝校区新生生活手册！','新生答疑 快递地址','','工大百科(学生整理)','[{\"url\": \"/kb-images/2c89d6485bd42de4.jpg\", \"desc\": \"校园快递服务站外景，学生在取快递。\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(23,'新生答疑','运动场地','场地预约\n\n微信小程序“运动场地预约”\n\n注意：\n\n1.校内人员请使用本人校园一卡通进行注册、预约。\n\n2.每日早7:00开放新的预约资源。\n\n3.若超过3次预约不到，系统将自动将该账号列入黑名单，此后无法进行任何预约操作。\n\n4.为避免健身资源浪费，预约后请按时到场，如因故无法到场，请提前取消预约。\n\n5.首次被列入黑名单的用户可到羽毛球场馆前台进行登记、并填写承诺书解除黑名单，受理时间为1到3个工作日。\n\n6.如遇法律、法规、国家政策、相关部门政策变化，法定不可抗力之情形，及体育馆各类大型活动，预约场地自动取消。\n\n篮球场/排球场\n\n位于南操场南侧，奥运餐厅东南侧\n\n开放时间：6:00-20:00\n\n田径场\n\n位于田径场\n\n北操场 全天开放\n\n南操场 开放时间：周一至周五 6:00-18:00，节假日全天关闭（实际使用全天开放）\n\n网球场\n\n位于南操场北侧\n\n开放时间：6:00-20:00\n\n健身房\n\n位于体育馆内北4口处，正对人文楼东门\n\n开放时间：周一至周五 10:00-22:00 周六和周日：9:00-22:00\n\n收费标准：\n\n乒乓球馆\n\n位于南田径场看台下，有23张专业球台。位于南操场西侧地下一层\n\n开放时间:\n\n周一、二、四（17:00-20:00)\n\n周三、六、日（12:00-20:00)\n\n周五（16:00-20:00)\n\n收费标准：\n\n地下训练馆\n\n位于游泳馆的北侧，有1块标准的篮球场地和1块标准的排球场地。优先保障了学校健美操课、排球课以及学校篮球队训练、排球队训练等场地使用。\n\n游泳馆\n\n位于游泳馆\n\n开放时间:\n\n周一、二、四（17:30-20:00)\n\n周三、六、日（12:00-17:00,17:30-20:00)\n\n周五（15:30-17:00,17:30-20:00)\n\n收费标准：\n\n注意：游泳馆每场次为1.5小时（12:00-17:00时段中任意1.5小时为一场次。超过1.5小时，按2场次计费；超过3小时，按3场次计费，以此类推，该时间段清场时间为17:00，请在17:00前离场。）首次游泳健身需携带体检表\n\n羽毛球馆\n\n位于奥运场馆一层，从北一门进入\n\n开放时间：\n\n周一至周五10：00——22：00\n\n周六、日及节假日08：00——22：00\n\n收费标准：','新生答疑 运动场地','','工大百科(学生整理)','[{\"url\": \"/kb-images/732f1a433a32a8f0.jpg\", \"desc\": \"微信小程序卡片：运动场地预约。\"}, {\"url\": \"/kb-images/dcde5614b0c34347.jpg\", \"desc\": \"田径场/足球场照片，远处学生军训列队，挂有红色标语横幅。\"}, {\"url\": \"/kb-images/572c75d7df23970a.jpg\", \"desc\": \"室外网球场照片，学生在打网球，背景为第四教学楼与艺术楼。\"}, {\"url\": \"/kb-images/19aa290e6de74185.jpg\", \"desc\": \"健身房内景照片，一排人在跑步机上跑步。\"}, {\"url\": \"/kb-images/67f0acea630cb241.jpg\", \"desc\": \"健身房收费标准表格。\"}, {\"url\": \"/kb-images/9d2311840efdf2d6.jpg\", \"desc\": \"乒乓球馆内景照片，多张红黑色乒乓球台排列。\"}]','enabled','2026-07-14 23:30:42','2026-07-14 15:44:34'),(24,'新生答疑','上课时间以及课表说明','上课时间\n\n温馨提醒：这个是全校时间安排表，并不代表每个人都有这么多的课，具体每天上到几点，看个人的选课安排\n\n课表说明\n\n每个人的课表都不一样，可以自行到教务管理系统查看，以下面课表为例：\n\n温馨提醒：\n\n大学是按大课来上的，一节大课为两节45分钟的课，中间休息5分钟，所以课表中对应的第一节课就是上课时间表中的第1节和第2节\n\n周三下午为公休日，绝大多数的专业都没有课程安排，可以自由安排时间','新生答疑 上课时间以及课表说明','','工大百科(学生整理)','[{\"url\": \"/kb-images/b135e47780ca5144.jpg\", \"desc\": \"两校区（校本部、通州校区）教学上课时间表\"}, {\"url\": \"/kb-images/b0c1e27b32b24bcb.jpg\", \"desc\": \"2023-2024学年第1学期电子信息工程专业（班号230262）的个人课程表示例\"}]','enabled','2026-07-14 23:56:41','2026-07-14 15:44:34'),(25,'新生答疑','学校常用公众号','温馨提示：手机阅读时请先点击二维码图片，再长按识别\n\n学校\n\n名称\n\n二维码\n\n简介\n\n北京工业大学\n\n不息为体，日新为道。这里是北京工业大学，工小 V 欢迎你~\n\n北工大图书馆\n\n提供随时随地的便捷图书馆服务\n\nBJUT教务处\n\n选课、补考、成绩、转专业等学习相关的咨询\n\n北工大后勤\n\n后勤保障处\n\n北工大学生树\n\n服务广大师生、为大家提供相关资讯\n\n平安北工大\n\n保卫处\n\n北京工业大学财务处\n\n财务相关政策和信息\n\n北京工业大学医院\n\n校医院\n\n北工大心理中心\n\n心理中心和心理协会官方账号\n\n北工大信息化\n\n信息化管理中心，校园网，一卡通等服务\n\n北京工业大学就业中心\n\n招聘信息、就业新闻、就业活动\n\n北京工业大学学生会\n\n学生会\n\n中蓝校区管理委员会\n\n中蓝校区相关资讯\n\n学院\n\n名称\n\n二维码\n\n简介\n\n北京工业大学国际学院\n\n学校、学部各类新闻资讯\n\n北京工业大学信息学部\n\n信息学部\n\n北京工业大学文法学部\n\n弘扬人文情怀,担当社会责任\n\n北工大经管研究生教育\n\n经管学院平台，发布新闻资讯、通知公告\n\n北京工业大学樊恭烋荣誉学院\n\nEducating Engineering Leadership\n\n北京工大学材料与制造学部\n\n材料与制造学部\n\n工大城建\n\n城载梦想、建铸辉煌，展示师生风采、传递校园动态\n\n北京都柏林国际学院\n\n校园信息发布','新生答疑 学校常用公众号','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(26,'新生答疑','校园网、VPN、校园卡都是啥？','有许多新生都弄混了这两个概念，特此写一篇百科来解释一下\n\n校园网\n\n校园网也就是咱们常说的内网，一般指的是学校的 wifi（也有网线插口可以用）\n\n开学了在学校里面，直接使用学号和密码登录，不需要办理任何手续\n\n手机和电脑都能连接（通俗一点来说就和你家里面的 wifi 性质差不多）\n\n每个月学校免费送 30G 流量，当然你也可以加钱买更多流量，具体看 \n校园网套餐\n\n校园卡\n\n校园卡一般指的是就是联通卡，电信卡，移动卡这种电话卡\n\n和学校没有关系，不办不影响在校的任何学习和生活\n\n看你自己的个人需求，一般来说就是便宜一点，流量多一点，\n\n外地学生的话，可以考虑办一个，流量多一点也方便\n\nVPN\n\n前面说了校园网必须要在学校里面使用（好比你在外面总不能连家里的 wifi 吧）\n\n但是如果周六日或者假期你不在学校，但是又需要上学校的内网查资料啥的，怎么办？\n\n此时就需要使用 VPN 了，具体怎么操作看 \n校园网VPN指南','新生答疑 校园网、VPN、校园卡都是啥？','','工大百科(学生整理)',NULL,'enabled','2026-07-14 15:44:34','2026-07-14 15:44:34'),(27,'新生答疑','学号各个数字的含义','本科生学号说明\n\n温馨提示：\n\n由于之前学院合并为学部，后来学部又拆分为学院，但是代码却没更新，所以同一个学院可能会有多个代码\n\n比如 02（原电控学院），07（原计算机学院），08（原软件学院）\n\n具体现在什么代码对应什么学院可以看 \n2024级新生课表\n\n相关资料\n\n见证历史！北工大学部又改学院了~','新生答疑 学号各个数字的含义','','工大百科(学生整理)','[{\"url\": \"/kb-images/258e3da2d69a93fb.jpg\", \"desc\": \"学号数字含义图解，以23010328为例拆解各段含义\"}]','enabled','2026-07-14 23:30:42','2026-07-14 15:44:34'),(28,'新生答疑','学院划分及专业方向','本文介绍工大的各个学院，以及每个学部下的专业以及细分方向，方便新生们了解整个学校的教学情况\n\n计算机学院\n\n信息安全（实验班）\n\n数字媒体技术\n\n计算机科学与技术（实验班）\n\n软件工程（实验班）\n\n计算机科学与技术\n\n物联网工程\n\n信息科学技术学院\n\n人工智能\n\n电子信息工程（实验班）\n\n电子科学与技术（实验班）\n\n自动化\n\n通信工程\n\n机器人工程\n\n电子信息工程\n\n测控技术与仪器\n\n外国语学院\n\n英语\n\n材料科学与工程学院\n\n资源循环科学与工程（按材料类（实验班）大类招生）\n\n纳米材料与技术（按材料类（实验班）大类招生）\n\n材料科学与工程（按材料类（实验班）大类招生）\n\n焊接技术与工程（按材料类（实验班）大类招生）\n\n应用化学\n\n新能源材料与器件（按材料类（实验班）大类招生）\n\n机械与能源工程学院\n\n机械工程（按机械类大类招生）\n\n智能制造工程（按机械类大类招生）\n\n能源与动力工程（按照能源动力类大类招生）\n\n新能源科学与工程（新能源和环科双学士学位）\n\n新能源科学与工程（按照能源动力类大类招生）\n\n建筑工程学院\n\n建筑环境与能源应用工程（按土木类大类招生）\n\n给排水科学与工程（按土木类大类招生）\n\n智能建造\n\n土木工程（茅以升班）\n\n土木工程（按土木类大类招生）\n\n建筑与城市规划学院\n\n城乡规划（五年制）\n\n建筑学（五年制）\n\n城市交通学院\n\n交通工程（按交通运输类（实验班）大类招生）\n\n交通设备与控制工程（按交通类（实验班）大类招生）\n\n数学统计学与力学学院\n\n数学与应用数学（按数学类大类招生）\n\n信息与计算科学（按数学类大类招生）\n\n统计学\n\n物理与光电工程学院\n\n应用物理学\n\n光电信息科学与工程\n\n化学与生命科学学院\n\n化学生物学\n\n生物医学工程\n\n生物技术（实验班）\n\n环境科学与工程学院\n\n环境工程（按环境科学与工程类大类招生）\n\n环境科学（按环境科学与工程类大类招生）\n\n经济与管理学院\n\n工商管理\n\n会计学\n\n信息管理与信息系统\n\n经济统计学\n\n国际经济与贸易\n\n金融学\n\n大数据管理与应用\n\n法学\n\n社会学（按社会学类大类招生）\n\n社会工作（按社会学类大类招生）\n\n艺术设计学院\n\n工业设计（普通类）\n\n雕塑（艺术类专业，按美术学类大类招生）\n\n绘画（艺术类专业，按美术学类大类招生）\n\n数字媒体艺术（艺术类专业，按设计学类大类招生）\n\n工艺美术（艺术类专业，按设计学类大类招生）\n\n服装设计（艺术类专业，按设计学类大类招生）\n\n产品设计（艺术类专业，按设计学类大类招生）\n\n环境设计（艺术类专业，按设计学类大类招生）\n\n视觉传达设计（艺术类专业，按设计学类大类招生）\n\n北京一都柏林国际学院\n\n物联网工程（中外合作办学）TheInternet of Things Engineering\n\n软件工程（中外合作办学）Software 